pragma solidity ^0.8.24;

contract Counter {
    uint256 public count; // state variable in storage

    event Incremented(address indexed by, uint256 newValue);

    function increment() external {
        count += 1;
        emit Incremented(msg.sender, count);
    }
}

pragma solidity ^0.8.24;

contract Locations {
    uint256[] public nums; // storage

    function sumCalldata(uint256[] calldata input) external pure returns (uint256 s) {
        for (uint256 i; i < input.length; i++) s += input[i]; // read-only, cheap
    }

    function bump(uint256 i) external {
        uint256[] storage ref = nums; // pointer to storage
        ref[i] += 1;                    // persists on-chain
    }
}

pragma solidity ^0.8.24;

contract Types {
    struct Point { uint256 x; uint256 y; }
    Point public p;

    function valueCopy() external pure returns (uint256) {
        uint256 a = 5;
        uint256 b = a; // independent copy
        b += 1;
        return a;      // still 5
    }

    function refAlias() external {
        Point storage ref = p; // alias
        ref.x = 42;            // updates p.x
    }
}

pragma solidity ^0.8.24;

contract Balances {
    mapping(address => uint256) public balanceOf;
    mapping(address => bool) private _known;
    address[] private _holders;

    function deposit() external payable {
        if (!_known[msg.sender]) {
            _known[msg.sender] = true;
            _holders.push(msg.sender);
        }
        balanceOf[msg.sender] += msg.value;
    }
}

