pragma solidity ^0.8.24;

contract Guards {
    error InsufficientBalance(uint256 available, uint256 required);
    mapping(address => uint256) public bal;

    function withdraw(uint256 amount) external {
        uint256 available = bal[msg.sender];
        if (amount > available) revert InsufficientBalance(available, amount);
        bal[msg.sender] = available - amount;
        assert(bal[msg.sender] <= available); // invariant
    }
}

pragma solidity ^0.8.24;

contract Overflow {
    function safeAdd(uint8 a, uint8 b) external pure returns (uint8) {
        return a + b; // reverts on overflow since 0.8
    }

    function loopSum(uint256 n) external pure returns (uint256 s) {
        for (uint256 i; i < n;) {
            s += i;
            unchecked { ++i; } // safe, saves gas
        }
    }
}

