pragma solidity ^0.8.24;

contract SafeVault {
    mapping(address => uint256) public balance;
    bool private _locked;

    modifier nonReentrant() {
        require(!_locked, "reentrant");
        _locked = true;
        _;
        _locked = false;
    }

    function withdraw(uint256 amount) external nonReentrant {
        require(balance[msg.sender] >= amount, "low balance"); // checks
        balance[msg.sender] -= amount;                          // effects
        (bool ok, ) = payable(msg.sender).call{value: amount}(""); // interaction
        require(ok, "transfer failed");
    }
}

pragma solidity ^0.8.24;

contract Proxy {
    address public implementation; // slot 0 must match logic layout

    function upgrade(address impl) external { implementation = impl; }

    fallback() external payable {
        address impl = implementation;
        assembly {
            calldatacopy(0, 0, calldatasize())
            let ok := delegatecall(gas(), impl, 0, calldatasize(), 0, 0)
            returndatacopy(0, 0, returndatasize())
            switch ok
            case 0 { revert(0, returndatasize()) }
            default { return(0, returndatasize()) }
        }
    }
}
